## 2. The C/C++ stub (`blocksci_stubs.c`)

> **NOTE** – The file must be compiled with a C++ compiler (`g++`/`clang++`) because it
> links against BlockSci’s C++ API.  All exported symbols are declared `extern "C"` so that
> the OCaml runtime can find them.

```c
/*----------------------------------------------------------------------
   blocksci_stubs.c – OCaml <-> BlockSci bridge
   ----------------------------------------------------------------------*/

#define CAML_NAME_SPACE          /* avoid name clashes */
#include <caml/mlvalues.h>
#include <caml/memory.h>
#include <caml/callback.h>
#include <caml/custom.h>
#include <caml/alloc.h>
#include <caml/fail.h>
#include <caml/bigarray.h>
#include <caml/threads.h>

#include <string>
#include <cstdint>

/* ----------------------------------------------------------------------
   Minimal BlockSci façade – replace the includes below with the real
   BlockSci headers you have on your system.
   ---------------------------------------------------------------------- */
extern "C" {
    // Forward‑declare the real BlockSci classes we need.
    class Block;
    class Chain;
    class BlockIterator;
}

/* ----------------------------------------------------------------------
   Global state – a single Chain instance is kept for the whole process.
   ---------------------------------------------------------------------- */
static Chain* g_chain = nullptr;

/* ----------------------------------------------------------------------
   Helper: turn a raw Block* into an OCaml custom value.
   The value is *ephemeral*: we allocate it once and then overwrite the
   pointer for every iteration step.  Users must not keep a reference
   after the callback returns.
   ---------------------------------------------------------------------- */
static struct custom_operations block_ops = {
    "BlockSci.block",
    /* finalize */      nullptr,
    /* compare */       nullptr,
    /* hash */          nullptr,
    /* serialize */    nullptr,
    /* deserialize */  nullptr,
    /* compare_ext */  nullptr,
    /* fixed_length */  0
};

static inline value make_block_val(Block* blk)
{
    // Allocate a custom block that just stores a raw pointer.
    value v = caml_alloc_custom(&block_ops, sizeof(Block*), 0, 1);
    Block** p = (Block**)Data_custom_val(v);
    *p = blk;
    return v;
}

/* ----------------------------------------------------------------------
   Accessor helpers – each fetches the underlying C++ object and converts
   the result to an OCaml value.
   ---------------------------------------------------------------------- */
static Block* block_of_val(value v)
{
    Block** p = (Block**)Data_custom_val(v);
    return *p;
}

/* ----------------------------------------------------------------------
   Public entry points
   ---------------------------------------------------------------------- */

/* Initialise the library – open a Chain on the given path. */
extern "C" CAMLprim value caml_blocksci_init(value v_path)
{
    CAMLparam1(v_path);
    CAMLlocal1(v_res);
    const char* path = String_val(v_path);

    if (g_chain != nullptr) {
        caml_failwith("BlockSci already initialised");
    }

    try {
        // The real BlockSci call – replace with the appropriate constructor.
        g_chain = new Chain(path);
    } catch (const std::exception& e) {
        caml_failwith(e.what());
    }

    CAMLreturn(Val_unit);
}

/* ----------------------------------------------------------------------
   iter_blocks – fast version that *ignores* OCaml exceptions.
   ---------------------------------------------------------------------- */
extern "C" CAMLprim value caml_blocksci_iter_blocks(value v_cb)
{
    CAMLparam1(v_cb);
    CAMLlocal1(v_blk);
    if (g_chain == nullptr) caml_failwith("BlockSci not initialised");

    // Acquire the OCaml runtime lock because we may run for a long time.
    caml_release_runtime_system();

    try {
        // The real iterator type – replace with BlockSci’s iterator.
        BlockIterator it = g_chain->blocks_begin();
        BlockIterator end = g_chain->blocks_end();

        for (; it != end; ++it) {
            Block* blk = *it;   // *it yields a Block*
            // Re‑use the same OCaml value for every iteration step.
            v_blk = make_block_val(blk);
            // The callback is a normal OCaml function (type block -> unit).
            caml_callback(v_cb, v_blk);
        }
    } catch (const std::exception& e) {
        // Restore the runtime before raising.
        caml_acquire_runtime_system();
        caml_failwith(e.what());
    }

    caml_acquire_runtime_system();   // re‑enter OCaml world
    CAMLreturn(Val_unit);
}

/* ----------------------------------------------------------------------
   iter_blocks_exn – version that propagates OCaml exceptions.
   ---------------------------------------------------------------------- */
extern "C" CAMLprim value caml_blocksci_iter_blocks_exn(value v_cb)
{
    CAMLparam1(v_cb);
    CAMLlocal1(v_blk);
    if (g_chain == nullptr) caml_failwith("BlockSci not initialised");

    caml_release_runtime_system();

    try {
        BlockIterator it = g_chain->blocks_begin();
        BlockIterator end = g_chain->blocks_end();

        for (; it != end; ++it) {
            Block* blk = *it;
            v_blk = make_block_val(blk);
            // Use caml_callback_exn so that OCaml exceptions are caught.
            value exn = caml_callback_exn(v_cb, v_blk);
            if (Is_exception_result(exn)) {
                caml_acquire_runtime_system();
                caml_raise(exn);
            }
        }
    } catch (const std::exception& e) {
        caml_acquire_runtime_system();
        caml_failwith(e.what());
    }

    caml_acquire_runtime_system();
    CAMLreturn(Val_unit);
}

/* ----------------------------------------------------------------------
   Accessors – each simply forwards to the underlying C++ method.
   ---------------------------------------------------------------------- */

/* block_hash : block -> string */
extern "C" CAMLprim value caml_blocksci_block_hash(value v_blk)
{
    CAMLparam1(v_blk);
    Block* blk = block_of_val(v_blk);
    // Assume Block has a method std::string hash() returning hex string.
    std::string h = blk->hash();
    CAMLreturn(caml_copy_string(h.c_str()));
}

/* block_height : block -> int */
extern "C" CAMLprim value caml_blocksci_block_height(value v_blk)
{
    CAMLparam1(v_blk);
    Block* blk = block_of_val(v_blk);
    // Assume Block has a method uint32_t height() const;
    uint32_t h = blk->height();
    CAMLreturn(Val_int(h));
}

/* block_timestamp : block -> int64 */
extern "C" CAMLprim value caml_blocksci_block_timestamp(value v_blk)
{
    CAMLparam1(v_blk);
    Block* blk = block_of_val(v_blk);
    // Assume Block has a method int64_t timestamp() const;
    int64_t t = blk->timestamp();
    CAMLreturn(caml_copy_int64(t));
}

/* ----------------------------------------------------------------------
   fold_blocks – a pure OCaml‑level combinator built on top of iter_blocks_exn.
   ---------------------------------------------------------------------- */
extern "C" CAMLprim value caml_blocksci_fold_blocks(value v_f, value v_acc)
{
    CAMLparam2(v_f, v_acc);
    CAMLlocal1(v_new_acc);
    // The fold is implemented in OCaml; we only need a tiny wrapper that
    // forwards the callback to the supplied function.
    // The wrapper closure captures [v_f] and returns a new accumulator each time.
    value* closure = caml_stat_alloc(sizeof(value));
    *closure = caml_copy_root(v_f);   // keep it alive

    // Helper that OCaml will call for each block.
    static value fold_cb(value v_blk) {
        CAMLparam1(v_blk);
        CAMLlocal2(v_f_local, v_res);
        v_f_local = caml_copy_root(*((value*)caml_get_global_data()));
        v_res = caml_callback2(v_f_local, caml_copy_root(v_acc), v_blk);
        // Update the accumulator for the next iteration.
        v_acc = v_res;
        CAMLreturn(Val_unit);
    }

    // Unfortunately we cannot pass a C function pointer directly to the
    // iterator, so we just reuse iter_blocks_exn with a small OCaml wrapper.
    // The wrapper is written in OCaml (see the .ml file below).

    // The actual implementation lives in the .ml file; here we only
    // provide the primitive that the .ml code will call.
    caml_failwith("fold_blocks: not implemented in C – use the OCaml version");
    CAMLreturn(v_acc);
}
```

