## 3. Minimal OCaml implementation of `fold_blocks`

Only a few lines of OCaml are needed; the rest of the library is in the
C stub above.

```ocaml
(* blocksci.ml – thin wrappers around the primitives defined in the .c file *)

external init : string -> unit = "caml_blocksci_init"
external iter_blocks : (block -> unit) -> unit = "caml_blocksci_iter_blocks"
external iter_blocks_exn : (block -> unit) -> unit = "caml_blocksci_iter_blocks_exn"
external block_hash : block -> string = "caml_blocksci_block_hash"
external block_height : block -> int = "caml_blocksci_block_height"
external block_timestamp : block -> int64 = "caml_blocksci_block_timestamp"

let fold_blocks f init =
  let acc = ref init in
  iter_blocks_exn (fun blk ->
    acc := f !acc blk
  );
  !acc
```

